// --- Add to COMPUTER: SET 1 (Hardware & Fundamentals) ---
questionBank.computer.set1.push(
    { q: "Which CPU architecture is utilized by almost all modern smartphones and Apple M-series chips due to its high power efficiency?", options: ["x86", "x64", "ARM (RISC)", "PowerPC"], ans: 2, exp: "Advanced RISC Machine (ARM) architecture uses a simplified instruction set, making it incredibly power-efficient compared to traditional x86 desktop chips." },
    { q: "What is the physical difference between 'DIMM' and 'SO-DIMM' RAM modules?", options: ["DIMM is for DDR3; SO-DIMM is for DDR4", "DIMM is for desktop motherboards; SO-DIMM is half the length and designed for laptops", "DIMM is volatile; SO-DIMM is non-volatile", "SO-DIMM requires liquid cooling"], ans: 1, exp: "Small Outline Dual In-line Memory Modules (SO-DIMM) are physically smaller to fit into compact mobile devices." },
    { q: "What does the '80 Plus' certification on a computer Power Supply Unit (PSU) indicate?", options: ["It provides exactly 80 watts of power", "It guarantees the power supply is at least 80% efficient at converting AC wall power to DC PC power", "It will last for 80 months", "It has 80 internal protection circuits"], ans: 1, exp: "An 80 Plus Gold or Platinum rating means less electricity is wasted as excess heat during the AC-to-DC conversion process." },
    { q: "In modern displays, what is 'V-Sync' designed to prevent?", options: ["Screen tearing, which occurs when the GPU sends frames faster than the monitor can refresh", "Dead pixels", "Monitor burn-in", "Color distortion"], ans: 0, exp: "Vertical Synchronization (V-Sync) forces the graphics card to wait and perfectly match the monitor's physical refresh rate." },
    { q: "What is 'N-Key Rollover' (NKRO) on a high-end keyboard?", options: ["The ability to press the 'N' key multiple times rapidly", "A feature that ensures every single keystroke is registered independently, even if all keys are pressed simultaneously", "A physical knob that controls volume", "A macro recording function"], ans: 1, exp: "NKRO prevents 'ghosting' where keyboards fail to register simultaneous inputs during fast typing or gaming." },
    { q: "Which hardware standard utilizes an optical fiber cable to transmit digital audio via red LED light?", options: ["HDMI", "3.5mm Jack", "TOSLINK (S/PDIF)", "Coaxial"], ans: 2, exp: "TOSLINK relies on light rather than electrical current to transmit pristine digital audio signals." },
    { q: "If a printer specification lists 'Duplex Printing', what does this mean?", options: ["It prints in two colors only", "It can automatically print on both the front and back sides of a single sheet of paper", "It has two separate paper trays", "It prints twice as fast"], ans: 1, exp: "An automatic duplexer flips the paper inside the printer to save paper and time." },
    { q: "In an AIO (All-In-One) liquid CPU cooler, what moves the liquid through the closed loop?", options: ["The radiator", "The motherboard", "The integrated pump", "The case fans"], ans: 2, exp: "The pump circulates the coolant from the hot CPU block to the radiator where it is cooled." },
    { q: "What is the standard physical width of a traditional desktop internal hard disk drive (HDD)?", options: ["1.5 inches", "2.5 inches", "3.5 inches", "5.25 inches"], ans: 2, exp: "Desktop HDDs are 3.5 inches. Laptops traditionally use smaller 2.5-inch drives." },
    { q: "What does 'Secure Boot' do in a modern UEFI system?", options: ["Encrypts the hard drive", "Requires a password to turn on the monitor", "Prevents unauthorized operating systems and low-level rootkits from loading during the boot process", "Deletes viruses automatically"], ans: 2, exp: "Secure Boot checks the digital signature of the OS bootloader before letting it run." },
    { q: "What is the difference between a PCIe x1 slot and a PCIe x16 slot?", options: ["x16 provides 16 times the data bandwidth (lanes) of an x1 slot", "x16 requires 16 separate power cables", "x1 is for video, x16 is for audio", "There is no speed difference"], ans: 0, exp: "Graphics cards require massive bandwidth and use x16 slots. Smaller cards like Wi-Fi adapters only need an x1 slot." },
    { q: "Which component stores the MAC address of a device?", options: ["The Hard Drive", "The Network Interface Card (NIC)", "The CPU", "The Monitor"], ans: 1, exp: "The MAC address is physically burned into the ROM of the network adapter at the factory." },
    { q: "What is a 'Membrane' keyboard?", options: ["A keyboard with individual mechanical switches under each key", "A keyboard that uses a single flexible rubber layer with conductive pads to register keypresses", "A keyboard that projects onto a desk", "A completely waterproof keyboard"], ans: 1, exp: "Membrane keyboards are cheaper and quieter, but lack the tactile feedback of mechanical switches." },
    { q: "In modern PC building, what is 'Cable Management' primarily intended to improve besides aesthetics?", options: ["Processor speed", "Airflow and cooling efficiency inside the computer case", "Hard drive storage capacity", "Internet bandwidth"], ans: 1, exp: "A tangled mess of cables blocks the front intake fans from pushing cool air to the CPU and GPU." },
    { q: "What is 'Overclocking'?", options: ["Running a clock app on the desktop", "Manually increasing the operating frequency (multiplier) of a CPU or GPU beyond the manufacturer's default specifications", "Deleting temporary files to speed up the PC", "Adding more RAM"], ans: 1, exp: "Overclocking increases performance but requires significantly more electrical power and generates much more heat." }
);

