questionBank.reasoning.medium.push(
    { q: "What is the mathematically exact angle between the minute hand and the hour hand of a clock at 5:15?", options: ["60 degrees", "67.5 degrees", "72.5 degrees", "90 degrees"], ans: 1, exp: "Formula: |30H - 5.5M|. |30(5) - 5.5(15)| = |150 - 82.5| = 67.5 degrees." },
    { q: "Pointing to a boy, a woman says, 'His mother is the only daughter of my mother.' How is the woman related to the boy?", options: ["Aunt", "Sister", "Mother", "Grandmother"], ans: 2, exp: "'The only daughter of my mother' refers to the woman herself. Therefore, the woman is the boy's mother." },
    { q: "A traveler moves 6 km North, turns exactly 90 degrees right and moves 8 km. What is the precise straight-line distance from the origin?", options: ["10 km", "12 km", "14 km", "100 km"], ans: 0, exp: "Facing North, a right turn points East. X=8, Y=6. Pythagorean theorem: √(6² + 8²) = √(36 + 64) = √100 = 10 km." },
    { q: "If the year 2012 (a leap year) started on a Sunday, what day of the week did the year 2013 start on?", options: ["Monday", "Tuesday", "Wednesday", "Thursday"], ans: 1, exp: "2012 contains 366 days, creating exactly 2 odd days. Sunday + 2 days = Tuesday." },
    { q: "In a coded language, all vowels are shifted +1, and all consonants are shifted -1. How would the word 'TEST' be coded?", options: ["SDRS", "UFTU", "SDTS", "UDRU"], ans: 0, exp: "T(consonant -1) = S. E(vowel +1) = F. S(consonant -1) = R. T(consonant -1) = S. Result: SFRS. Wait, options don't have SFRS. Let's fix the question.", options: ["SFRS", "SDTU", "UFTU", "SFRT"], ans: 0, exp: "T(-1)=S. E(+1)=F. S(-1)=R. T(-1)=S. Result: SFRS." },
    { q: "Find the missing number in the strict mathematical series: 1, 4, 27, 16, 125, 36, __", options: ["49", "216", "343", "512"], ans: 2, exp: "Two alternating series. Odd positions are cubes (1³, 3³, 5³, 7³). Even positions are squares (2², 4², 6²). Next is position 7: 7³ = 343." },
    { q: "Five students are ranked. A is taller than B but shorter than C. D is taller than E but shorter than B. Who is the absolute shortest?", options: ["A", "B", "D", "E"], ans: 3, exp: "Logic chain: C > A > B. And B > D > E. Combined: C > A > B > D > E. E is the shortest." },
    { q: "Find the missing number in the matrix: Row 1 (3, 4, 25), Row 2 (5, 6, 61), Row 3 (2, 8, ?)", options: ["64", "66", "68", "70"], ans: 2, exp: "Strict Logic: (Column 1)² + (Column 2)² = Column 3. (3²+4² = 9+16 = 25). For Row 3: 2² + 8² = 4 + 64 = 68." },
    { q: "In a queue, Amit is 15th from the front. Neha is 20th from the rear. There are exactly 3 people standing strictly between them. What is the MAXIMUM possible total number of people in the queue?", options: ["32", "35", "38", "40"], ans: 2, exp: "Maximum non-overlapping formula: Position L + Position R + Middle. 15 + 20 + 3 = 38." },
    { q: "Syllogism: All Tigers are Cats. All Cats are Animals. Conclusion: All Tigers are Animals.", options: ["True", "False", "Cannot be determined", "Partially true"], ans: 0, exp: "Tigers are 100% inside Cats. Cats are 100% inside Animals. Therefore, Tigers are unequivocally 100% inside Animals. True." },
    { q: "A clock gains exactly 1 minute every hour. If it is set correctly at 6:00 AM, what exact time will the hands show when the true, correct time is 6:00 PM the same day?", options: ["6:00 PM", "6:06 PM", "6:12 PM", "6:24 PM"], ans: 2, exp: "From 6 AM to 6 PM is exactly 12 hours. 12 hours * 1 minute gain = 12 minutes fast. It will display 6:12 PM." },
    { q: "If A$B means A is the brother of B. A#B means A is the sister of B. What does M $ N # P mean?", options: ["M is the aunt of P", "M is the father of P", "M is the uncle of P", "M is the brother of P"], ans: 3, exp: "M $ N means M is the brother of N. N # P means N is the sister of P. Therefore, M, N, and P are all siblings. M is the brother of P." },
    { q: "A person travels 15km South, turns exactly 90 degrees to their left, and travels. What cardinal direction are they moving in?", options: ["North", "South", "East", "West"], ans: 2, exp: "Facing South, a 90-degree left (anticlockwise) turn points the person precisely East." },
    { q: "If the word 'MAN' is logically coded as 'NZO', how is 'BOY' coded by shifting each letter forward by exactly one position (+1)?", options: ["CPZ", "CPX", "CPY", "APX"], ans: 0, exp: "B(+1)=C, O(+1)=P, Y(+1)=Z. Result: CPZ." },
    { q: "Solve the strict inequality chain: X > Y ≥ Z = W < V. Which conclusion is absolutely true?", options: ["X > W", "X < V", "Y = W", "Z > V"], ans: 0, exp: "Looking from X to W: X > Y ≥ Z = W. Since X is strictly greater than Y, and Y is greater than or equal to W, X MUST be strictly greater than W." }
);

// --- REASONING: HARD (Strict Logic) ---
questionBank.reasoning.hard.push(
    { q: "Syllogism: No A is B. Only a few B are C. Conclusion I: Some C are definitely not A. Conclusion II: All C can never be B.", options: ["Only I follows", "Only II follows", "Both I and II follow", "Neither follows"], ans: 0, exp: "B does not touch A. C overlaps B. The part of C that sits inside B can NEVER touch A. Therefore, some C are definitely not A (I is true). 'Only a few B are C' means some B are not C. It does NOT restrict C from being entirely inside B. Thus, all C COULD potentially be B (II is false)." },
    { q: "At what exact mathematical time between 3 and 4 o'clock are the hands of a clock perfectly opposite each other (180 degrees apart)?", options: ["49 1/11 minutes past 3", "45 minutes past 3", "48 3/11 minutes past 3", "50 2/11 minutes past 3"], ans: 0, exp: "Opposite Formula: Time = 5 * (H + 6) * 12/11 (because H < 6). 5 * 9 * 12/11 = 45 * 12/11 = 540 / 11 = 49 1/11 minutes." },
    { q: "What day of the week was February 29th, 2004?", options: ["Saturday", "Sunday", "Monday", "Tuesday"], ans: 1, exp: "2000 was a leap year. Years 2001, 2002, 2003 give 3 odd days. Jan 2004 (3), Feb 29 (1). Standard calculation formula points to Sunday." },
    { q: "A solid 4x4x4 cube is painted entirely green on the outside, then sliced into 64 smaller 1x1x1 cubes. Exactly how many of the smaller cubes have EXACTLY ONE face painted green?", options: ["8", "16", "24", "32"], ans: 2, exp: "Formula for one face painted: 6 * (n-2)². Since n=4, 6 * (4-2)² = 6 * 2² = 6 * 4 = 24. There are 4 central cubes on each of the 6 faces." },
    { q: "A drone flies 30 km East, turns exactly 90 degrees right and flies 40 km. It then turns exactly 90 degrees right and flies 30 km. What is the shortest straight-line distance from its starting point?", options: ["10 km", "30 km", "40 km", "50 km"], ans: 2, exp: "The drone flies a rectangular path. East 30 and West 30 cancel out exactly. It is left with exactly 40 km South of the starting point." },
    { q: "Coded Relations: A @ B means A is the husband of B. A # B means A is the sister of B. A $ B means A is the son of B. In the expression P $ Q @ R # S, how is P related to R?", options: ["Son", "Nephew", "Brother", "Father"], ans: 0, exp: "P is the son of Q. Q is the husband of R. Therefore, Q and R are parents (Q father, R mother). Since P is the son of Q, P is the son of R." },
    { q: "Eight people sit around a circular table facing the center. A sits third to the right of B. C sits second to the left of A. D sits exactly opposite to B. Who sits directly between A and B?", options: ["C", "D", "Someone else", "Cannot be determined"], ans: 2, exp: "If A is 3rd right of B, there are exactly 2 seats between them on that side. The person sitting exactly opposite B is D. The exact positions between A and B cannot be C (who is 2nd left of A). It's someone else." },
    { q: "Find the missing number in the strict algebraic series: 0, 7, 26, 63, 124, 215, __", options: ["342", "343", "344", "511"], ans: 0, exp: "The strict algebraic formula is (n³ - 1). For n=1: 1-1=0. n=2: 8-1=7. n=3: 27-1=26. n=4: 64-1=63. n=5: 125-1=124. n=6: 216-1=215. The next is n=7: 7³ - 1 = 343 - 1 = 342." },
    { q: "Data Sufficiency: Question: Among 5 friends A, B, C, D, E, who is the heaviest? Statement 1: A is heavier than B and C. Statement 2: D is lighter than E but heavier than A.", options: ["Statement 1 alone is sufficient", "Statement 2 alone is sufficient", "Both statements together are sufficient", "Both statements together are NOT sufficient"], ans: 2, exp: "From 1: A > B, C. From 2: E > D > A. Combining them: E > D > A > B, C. We can definitively say E is the heaviest. Both statements are needed." },
    { q: "A clock loses exactly 5 minutes every day (24 hours). It is set to the correct time at 12:00 Noon on Monday. What time will the clock display when the true, correct time is 12:00 Noon on Wednesday?", options: ["11:50 AM", "11:55 AM", "12:10 PM", "11:45 AM"], ans: 0, exp: "From Mon Noon to Wed Noon is exactly 48 hours (2 days). The clock loses 5 minutes per day. 2 days * 5 minutes = 10 minutes lost. True time is 12:00 PM; the clock will show 11:50 AM." },
    { q: "In a definitive coding matrix, 'pa re ta' equals 'birds fly high', 'ku re ma' equals 'planes fly fast', and 'ta ma lo' equals 'birds and planes'. Based STRICTLY on this matrix, what is the code for the word 'high'?", options: ["pa", "re", "ta", "cannot be determined"], ans: 0, exp: "'fly' is common to 1 & 2 (code 're'). 'birds' is common to 1 & 3 (code 'ta'). In statement 1 ('pa re ta'), the remaining code 'pa' must represent the remaining word 'high'." },
    { q: "Syllogism: All X are Y. No Y is Z. All Z are W. Conclusion: Some W are definitely not X.", options: ["True", "False", "Cannot be mathematically determined", "Partially true"], ans: 0, exp: "X is inside Y. Y cannot touch Z. Z is entirely inside W. Therefore, the part of W that consists of Z can NEVER touch Y (and by extension, X). Thus, 'Some W (the Z part) are definitely not X' is absolutely True." },
    { q: "A 3x3x3 solid cube is painted blue on all outside surfaces and cut into 27 smaller 1x1x1 cubes. Exactly how many small cubes have EXACTLY THREE faces painted?", options: ["4", "8", "12", "16"], ans: 1, exp: "Regardless of the cube size (n > 1), cubes with 3 faces painted are ALWAYS the corner cubes. A cube geometrically has exactly 8 corners." },
    { q: "Find the missing number in the alternating factor series: 2, 3, 6, 18, 108, __", options: ["1944", "1800", "2160", "1544"], ans: 0, exp: "The series utilizes progressive multiplication of the previous two terms. 2x3=6. 3x6=18. 6x18=108. Next is 18x108 = 1944." },
    { q: "Solve the strict inequality chain: K ≥ L = M > N < O. Which of the following conclusions is mathematically guaranteed to be true?", options: ["K > N", "K > O", "L < O", "M = O"], ans: 0, exp: "Looking from K to N: K ≥ L = M > N. Since K is greater than or equal to L/M, and L/M is strictly greater than N, K MUST be strictly greater than N." }
);
