// --- COMPUTER: SET 3 (Internet & Networking) ---
questionBank.computer.set3.push(
    { q: "In CIDR notation, what exactly does the '/24' in '192.168.1.0/24' signify mathematically?", options: ["The network runs at 24 Mbps", "The first 24 bits of the 32-bit IP address are locked as the network identifier, leaving 8 bits (256 addresses) for host devices", "There are exactly 24 computers on the network", "It uses IPv6"], ans: 1, exp: "A /24 subnet mask is 255.255.255.0. It provides exactly 254 usable host IP addresses (since .0 and .255 are reserved)." },
    { q: "In TCP networking, what is the 'Three-Way Handshake'?", options: ["A method for generating passwords", "The strict process (SYN, SYN-ACK, ACK) used to establish a reliable connection between a client and server before data is sent", "A protocol for sending emails", "A way to restart a router"], ans: 1, exp: "This handshake ensures both the sender and receiver are ready and synchronized before massive data transfer begins." },
    { q: "What does an 'AAAA Record' in a DNS configuration do?", options: ["It provides the highest level of security", "It maps a domain name mathematically to a 128-bit IPv6 address", "It blocks spam traffic", "It handles email routing"], ans: 1, exp: "An 'A Record' maps to a 32-bit IPv4 address. An 'AAAA Record' maps to the much longer IPv6 address." },
    { q: "What is the technical difference between 'Routing' and 'Switching'?", options: ["They are identical", "Switching operates at Layer 2 (MAC addresses) to connect devices on the SAME network; Routing operates at Layer 3 (IP addresses) to connect DIFFERENT networks", "Routing is wired, Switching is wireless", "Switching is for servers only"], ans: 1, exp: "Switches build local area networks (LANs). Routers connect LANs to Wide Area Networks (WANs) like the internet." },
    { q: "What does 'OFDMA' achieve in the Wi-Fi 6 (802.11ax) standard?", options: ["It encrypts the Wi-Fi password", "Orthogonal Frequency-Division Multiple Access allows the router to divide a single wireless channel into smaller sub-channels, transmitting data to multiple devices simultaneously", "It turns off the Wi-Fi at night", "It boosts the range by 10 miles"], ans: 1, exp: "OFDMA drastically reduces latency and congestion in crowded areas by servicing multiple devices in a single transmission." },
    { q: "Which routing protocol is categorized as a 'Path Vector' protocol and forms the core routing logic of the global internet?", options: ["OSPF", "EIGRP", "BGP (Border Gateway Protocol)", "RIP"], ans: 2, exp: "BGP makes routing decisions based on paths, network policies, and rule-sets to route traffic between massive Autonomous Systems." },
    { q: "What does the '802.1Q' networking standard dictate?", options: ["Wi-Fi speeds", "The formal standard for inserting a VLAN (Virtual LAN) tag into an Ethernet frame header, allowing multiple virtual networks to share one physical cable", "Bluetooth connectivity", "Fiber optic light frequencies"], ans: 1, exp: "VLAN tagging allows network switches to identify which virtual network a data packet belongs to." },
    { q: "In IPv6, what is 'Anycast' addressing?", options: ["Sending data to every single computer on Earth", "An addressing method where multiple servers share the exact same IP address, and the network routes the user's request to the physically closest server", "A method for encrypting data", "A broadcast to a local network"], ans: 1, exp: "Anycast is heavily used by Content Delivery Networks (CDNs) and DNS servers to provide ultra-fast, localized responses." },
    { q: "If a computer is assigned a subnet mask of 255.255.255.192 (/26), mathematically, how many usable host IP addresses are available in that specific subnet?", options: ["254", "128", "62", "30"], ans: 2, exp: "A /26 borrows 2 bits for the network, leaving 6 bits for hosts. 2^6 = 64. Subtract 2 (Network and Broadcast addresses) = 62 usable hosts." },
    { q: "What is the primary function of 'NAT' (Network Address Translation)?", options: ["To translate websites to English", "To modify IP address information in packet headers, allowing an entire private local network to communicate with the internet using a single public IP address", "To encrypt web traffic", "To speed up video streaming"], ans: 1, exp: "NAT is the reason IPv4 addresses haven't completely run out; millions of homes use private 192.168.x.x addresses behind one public IP." },
    { q: "Which protocol relies on UDP Port 67 and 68 to automate network configurations?", options: ["HTTP", "DNS", "DHCP", "FTP"], ans: 2, exp: "The Dynamic Host Configuration Protocol (DHCP) uses these ports to lease IP addresses to client devices." },
    { q: "What is a 'Reverse Proxy'?", options: ["A proxy used for illegal hacking", "A server that sits in front of backend web servers and forwards client requests to those servers, often providing load balancing, caching, and SSL termination", "A router that sends data backward", "A backup hard drive"], ans: 1, exp: "While a normal proxy protects clients going out to the internet, a reverse proxy protects servers from incoming internet traffic." },
    { q: "What does the Linux command 'netstat -tulnp' specifically display?", options: ["The CPU temperature", "A detailed list of all active, listening TCP and UDP network ports and the specific process ID (PID) utilizing them", "The contents of the hard drive", "The Wi-Fi password"], ans: 1, exp: "This command is critical for system administrators to check which services (like web or SSH servers) are open to the network." },
    { q: "What is the exact purpose of the 'TTL' (Time To Live) field in an IP packet header?", options: ["It dictates how many days the data is valid", "It mathematically limits the lifespan of data in a network; each router decreases the TTL by 1, and if it hits 0, the packet is destroyed to prevent infinite routing loops", "It sets the encryption strength", "It determines the download speed"], ans: 1, exp: "Without TTL, a misconfigured router could bounce a packet back and forth forever, eventually crashing the internet." },
    { q: "In the OSI Model, which layer is responsible for establishing, managing, and terminating communication sessions between two applications?", options: ["Layer 2 (Data Link)", "Layer 3 (Network)", "Layer 5 (Session)", "Layer 7 (Application)"], ans: 2, exp: "The Session Layer controls the dialogues (connections) between computers, determining who can speak and for how long." }
);

// --- COMPUTER: SET 4 (Storage & Memory) ---
questionBank.computer.set4.push(
    { q: "What is the mathematical requirement to build a 'RAID 6' array?", options: ["Exactly two drives", "A minimum of three drives", "A minimum of four drives, utilizing block-level striping with double distributed parity", "Solid state drives only"], ans: 2, exp: "Because RAID 6 calculates and writes two separate parity blocks, it can survive the simultaneous failure of two different hard drives." },
    { q: "In Solid State Drives (SSDs), what is the technical difference between SLC, MLC, TLC, and QLC flash memory?", options: ["The physical size of the drive", "The number of bits stored per individual memory cell (1, 2, 3, and 4 bits respectively), which dictates capacity, speed, and endurance", "The type of cable used", "The brand of the manufacturer"], ans: 1, exp: "SLC (1 bit per cell) is the fastest and lasts the longest but is expensive. QLC (4 bits per cell) is cheap and holds massive data, but wears out faster." },
    { q: "Why is 'Defragmentation' mathematically detrimental to a Solid State Drive (SSD)?", options: ["It makes the SSD too hot", "SSDs have no mechanical read head, so scattered data causes no speed penalty; defragmenting only performs unnecessary write cycles, permanently reducing the flash memory's lifespan", "It encrypts the SSD", "It deletes the operating system"], ans: 1, exp: "Flash memory degrades with every write. Moving data around just to make it 'neat' burns through the drive's limited write cycles for zero performance gain." },
    { q: "In enterprise storage, what is the strict architectural difference between a SAN and a NAS?", options: ["SAN is wireless, NAS is wired", "SAN provides block-level access over a dedicated high-speed network (Fiber Channel/iSCSI); NAS provides file-level access over standard Ethernet", "NAS is faster than SAN", "There is no difference"], ans: 1, exp: "Servers see a SAN volume as a raw, unformatted local hard drive. Servers see a NAS volume as a shared network folder." },
    { q: "What does 'LTO-8' refer to in enterprise IT storage?", options: ["A type of CPU cache", "An 8th generation Linear Tape-Open magnetic tape cartridge capable of holding 12 TB of raw uncompressed archival data", "A high-speed SSD protocol", "A cloud storage pricing tier"], ans: 1, exp: "Despite being 'old' technology, magnetic tape remains the absolute cheapest and most reliable medium for cold archival storage." },
    { q: "What does 'IOPS' measure in storage performance testing?", options: ["Internet Output Speed", "Input/Output Operations Per Second; an exact mathematical measurement of how many read/write tasks a drive can perform in one second", "Internal Optical Processing System", "Integrated Overclocking Performance"], ans: 1, exp: "An HDD might max out at 100 IOPS. A modern NVMe SSD can easily exceed 1,000,000 IOPS, making it vastly superior for database servers." },
    { q: "What is the primary function of the 'ZFS' file system developed by Sun Microsystems?", options: ["To format USB drives", "To provide immense storage capacities combined with continuous mathematical checksums to automatically detect and repair silent data corruption", "To run Windows games on Linux", "To encrypt emails"], ans: 1, exp: "ZFS is the gold standard for enterprise data integrity, ensuring 'bit rot' never destroys archival files." },
    { q: "In modern motherboard architecture, how many PCIe lanes does a standard NVMe M.2 SSD physically utilize to achieve maximum speed?", options: ["x1 (1 lane)", "x4 (4 lanes)", "x8 (8 lanes)", "x16 (16 lanes)"], ans: 1, exp: "A standard NVMe drive uses an x4 PCIe connection. Graphics cards use x16." },
    { q: "What does 'eMMC' (Embedded MultiMediaCard) storage represent?", options: ["Enterprise server storage", "Cheap, relatively slow flash storage soldered directly onto the motherboard, typically found in budget laptops and smartphones", "Magnetic tape storage", "High-speed RAM"], ans: 1, exp: "eMMC acts like a permanently attached SD card. It is significantly slower than true NVMe or SATA SSDs." },
    { q: "What is 'Thin Provisioning' in virtualized storage environments?", options: ["Making laptops thinner", "A mathematical allocation method where a server is told it has a 5TB drive, but the storage array only allocates physical disk space exactly as data is actually written", "Erasing data securely", "Compressing files"], ans: 1, exp: "This prevents massive amounts of expensive physical storage from sitting empty and unused." },
    { q: "What does the SATA 'AHCI' protocol do?", options: ["Controls graphics cards", "Advanced Host Controller Interface; it specifies the operation of SATA host bus adapters, enabling features like Hot Swapping and Native Command Queuing (NCQ)", "Provides Wi-Fi", "Encrypts hard drives"], ans: 1, exp: "AHCI replaced older IDE protocols to unlock the full potential of SATA drives." },
    { q: "In SSD architecture, what is 'Over-Provisioning'?", options: ["Selling an SSD for more than it's worth", "Dedicating a hidden portion of the physical flash memory capacity solely to the SSD controller to assist with wear leveling and garbage collection", "Installing too many SSDs", "Formatting the drive multiple times"], ans: 1, exp: "A 500GB SSD might actually have 512GB of physical flash inside, keeping the extra 12GB hidden to replace dead cells over time." },
    { q: "What does 'Deduplication' achieve in enterprise backup storage?", options: ["It duplicates files for safety", "It mathematically analyzes data blocks and eliminates redundant copies, saving only one unique instance of the data and replacing others with a tiny reference pointer", "It deletes old files automatically", "It encrypts data twice"], ans: 1, exp: "If 100 employees save the exact same 5MB PDF, deduplication ensures the server only stores 5MB total, not 500MB." },
    { q: "What is the physical size of an 'M.2 2280' SSD?", options: ["22 inches by 80 inches", "22 millimeters wide and 80 millimeters long", "220 millimeters long", "22 centimeters wide"], ans: 1, exp: "The numerical designation strictly defines the physical dimensions of the drive, ensuring it fits the motherboard slot." },
    { q: "Which of the following defines 'Cold Storage' in cloud data centers?", options: ["Servers placed in a refrigerator", "An ultra-low-cost storage tier for data that is rarely accessed, where retrieval mathematically takes hours or days rather than milliseconds", "A broken hard drive", "Storing files on a USB drive"], ans: 1, exp: "AWS Glacier is an example of cold storage, heavily relying on automated magnetic tape libraries." }
);

// --- COMPUTER: SET 5 (Security & Generations) ---
questionBank.computer.set5.push(
    { q: "In cybersecurity, what is the strict mathematical difference between 'Hashing' and 'Encryption'?", options: ["They are exactly the same", "Encryption is a two-way mathematical function designed to be decrypted with a key; Hashing is a one-way mathematical function designed to create a fixed-length signature that cannot be reversed", "Hashing is for hardware, Encryption is for software", "Hashing is faster but less secure"], ans: 1, exp: "You encrypt an email so the recipient can read it. You hash a password so that NO ONE (not even the database admin) can read it." },
    { q: "What is a 'CSRF' (Cross-Site Request Forgery) attack?", options: ["Hacking a Wi-Fi password", "An attack that tricks an authenticated user's web browser into executing an unwanted, unauthorized mathematical action on a trusted site without their knowledge", "A physical attack on a server", "Flooding a server with ping requests"], ans: 1, exp: "For example, tricking you into clicking a link that silently commands your logged-in bank account to transfer money." },
    { q: "In Public Key Infrastructure (PKI), if Alice wants to send a strictly confidential, encrypted message to Bob, which key does Alice use to lock (encrypt) the message?", options: ["Alice's Private Key", "Alice's Public Key", "Bob's Public Key", "Bob's Private Key"], ans: 2, exp: "Alice encrypts the message using Bob's mathematical Public Key. Only Bob possesses the corresponding Private Key required to decrypt it." },
    { q: "What is 'Spear Phishing' compared to standard 'Phishing'?", options: ["Spear phishing targets marine biologists", "Standard phishing sends identical, generic emails to millions of people; Spear Phishing uses highly researched, customized intelligence to target a specific individual or organization", "Spear phishing uses text messages only", "There is no difference"], ans: 1, exp: "A spear phishing email might use your actual boss's name and reference a specific ongoing project to gain your trust." },
    { q: "What is the primary function of an 'IPS' (Intrusion Prevention System) as opposed to an 'IDS' (Intrusion Detection System)?", options: ["IPS generates viruses", "IDS strictly monitors and alerts administrators to suspicious traffic; IPS is positioned inline and actively blocks or drops the malicious traffic mathematically in real-time", "IPS is a physical lock on a door", "IDS is for home use only"], ans: 1, exp: "IDS is a burglar alarm (it makes noise). IPS is an automated security door (it stops the intruder)." },
    { q: "In malware analysis, what is a 'Rootkit'?", options: ["A kit to build a computer", "A highly sophisticated type of malware designed to mathematically alter the operating system kernel to grant administrative access while completely hiding its own processes from antivirus scanners", "A virus that deletes Word documents", "A simple phishing email"], ans: 1, exp: "Because rootkits operate at the deepest level of the OS, standard antivirus software often cannot see them at all." },
    { q: "What is the 'Principle of Least Privilege' (PoLP)?", options: ["A rule that limits internet speed", "A strict security architecture doctrine stating that a user, application, or process should be granted only the absolute minimum permissions necessary to perform its specific task", "A rule that bans all passwords", "A method for encrypting hard drives"], ans: 1, exp: "If a receptionist's account is compromised, PoLP ensures the hacker cannot use that account to access or delete the SQL database." },
    { q: "What does 'SQL Injection' (SQLi) mathematically target?", options: ["The computer's CPU cache", "The website's backend database; attackers input raw SQL commands into a text box, tricking the server into executing unauthorized database queries", "The Wi-Fi router's firmware", "The physical RAM modules"], ans: 1, exp: "A successful SQLi attack can bypass logins, alter balances, or dump massive lists of user passwords." },
    { q: "What does 'Ransomware' mathematically do to a victim's computer?", options: ["It deletes the operating system", "It utilizes incredibly strong asymmetric encryption algorithms to mathematically lock the user's files, requiring a unique, externally held private key to decrypt them", "It steals RAM processing power to mine crypto", "It uploads all files to a public server"], ans: 1, exp: "Without the private key held by the attacker, mathematically decrypting the files (e.g., AES-256) would take millions of years." },
    { q: "What is a 'Zero-Day' vulnerability?", options: ["A virus that activates at exactly midnight", "A software security flaw that is known to attackers but completely unknown to the software vendor, meaning zero patches or defenses currently exist", "An attack that takes zero seconds", "A secure network protocol"], ans: 1, exp: "Zero-days are highly prized and sold on the dark web for massive amounts of money." },
    { q: "What is the strict purpose of 'Salting' a password hash?", options: ["To make the password easier to type", "To append a unique, randomly generated cryptographic string to the user's password before hashing it, mathematically preventing Rainbow Table attacks", "To encrypt the database a second time", "To enforce capital letters in the password"], ans: 1, exp: "Because of the unique salt, two users with the password '12345' will have completely different, unrecognizable hashes in the database." },
    { q: "What is a 'Botnet'?", options: ["An automated customer service chat AI", "A massive network of malware-infected private computers ('zombies') mathematically controlled remotely by an attacker to launch coordinated attacks", "A secure internal corporate network", "A cluster of legitimate web servers"], ans: 1, exp: "Botnets are the primary infrastructure used to launch devastating Distributed Denial of Service (DDoS) attacks." },
    { q: "What defines 'Zero Trust' network architecture?", options: ["Trusting devices inside the office building, but not outside", "A strict framework assuming the network is always hostile; it never trusts any entity by default and mathematically requires continuous authentication and authorization for every single action", "Banning all external emails", "Removing all passwords"], ans: 1, exp: "In Zero Trust, simply being plugged into the corporate Ethernet port grants you exactly zero access to resources." },
    { q: "What is 'Steganography'?", options: ["Typing encrypted code rapidly", "The practice of mathematically concealing a secret message, file, or payload inside an ordinary, non-suspicious file (such as altering the least significant bits of a JPEG image)", "A method of password cracking", "A physical lock on a server rack"], ans: 1, exp: "While encryption makes data unreadable, steganography makes the existence of the data entirely invisible." },
    { q: "Which generation of computers introduced the concept of the 'Microprocessor', combining thousands of integrated circuits onto a single silicon chip?", options: ["First Generation", "Second Generation", "Third Generation", "Fourth Generation"], ans: 3, exp: "The Fourth Generation (1971-Present) birthed the personal computer revolution by shrinking room-sized machines down to a single chip." }
);

// --- REASONING: EASY (Strict Logic) ---
questionBank.reasoning.easy.push(
    { q: "Strict Analogy: Telescope is to Distant as Microscope is to:", options: ["Heavy", "Minute (Tiny)", "Bright", "Loud"], ans: 1, exp: "A telescope magnifies objects that are extremely distant. A microscope magnifies objects that are extremely minute (tiny)." },
    { q: "Find the precise next number in the arithmetic series: 11, 23, 35, 47, 59, __", options: ["69", "70", "71", "72"], ans: 2, exp: "This is an arithmetic progression. The sequence strictly adds exactly 12 each time. 59 + 12 = 71." },
    { q: "Which word does NOT belong in this specific semantic group?", options: ["Hexagon", "Octagon", "Circle", "Pentagon"], ans: 2, exp: "A circle is composed of a continuous curve. The others are polygons formed strictly by straight line segments." },
    { q: "If A = 3, B = 4, C = 5, what is the exact sum of the alphabetical positions in the word 'DOG' based on this shifted rule?", options: ["26", "29", "32", "35"], ans: 2, exp: "The rule is (Alphabetical Position + 2). D(4+2=6). O(15+2=17). G(7+2=9). Sum: 6 + 17 + 9 = 32." },
    { q: "Find the next precise term in the sequence: 2, 4, 16, 256, __", options: ["512", "1024", "4096", "65536"], ans: 3, exp: "The sequence mathematically squares the previous number. 2² = 4. 4² = 16. 16² = 256. 256² = 65536." },
    { q: "Author is to Pen as Painter is to:", options: ["Canvas", "Brush", "Gallery", "Museum"], ans: 1, exp: "A pen is the physical tool used by an author to create. A brush is the physical tool used by a painter to create." },
    { q: "Which word does NOT logically belong?", options: ["Iron", "Copper", "Aluminum", "Steel"], ans: 3, exp: "Iron, Copper, and Aluminum are pure elemental metals. Steel is an alloy (a mixture of iron and carbon)." },
    { q: "If 'BOOK' is mathematically coded as '4332' (where B=4, O=3, K=2), how is 'KOBO' coded?", options: ["2343", "2334", "3243", "4233"], ans: 1, exp: "Direct positional mapping based on the provided key: K = 2, O = 3, B = 4, O = 3. Result: 2334." },
    { q: "Complete the logical pattern: January, April, July, __", options: ["August", "September", "October", "November"], ans: 2, exp: "The sequence strictly advances by jumping exactly 3 months forward. July + 3 months = October." },
    { q: "Anemometer is to Wind as Odometer is to:", options: ["Distance", "Time", "Pressure", "Weight"], ans: 0, exp: "An anemometer physically measures wind speed. An odometer physically measures the distance traveled by a vehicle." },
    { q: "Find the next number in the alternating series: 10, 15, 13, 18, 16, __", options: ["19", "20", "21", "22"], ans: 2, exp: "The series mathematically alternates: +5, -2. 10(+5)=15. 15(-2)=13. 13(+5)=18. 18(-2)=16. Next is 16(+5) = 21." },
    { q: "Which word does NOT belong in this physical group?", options: ["Root", "Stem", "Leaf", "Soil"], ans: 3, exp: "Root, Stem, and Leaf are biological components of a plant. Soil is the environment in which they grow." },
    { q: "If BLUE is coded as 40 (2+12+21+5), what is the exact sum of the word SKY?", options: ["55", "56", "57", "58"], ans: 0, exp: "S(19) + K(11) + Y(25) = 55." },
    { q: "Fish is to Aquarium as Bird is to:", options: ["Nest", "Tree", "Aviary", "Sky"], ans: 2, exp: "An aquarium is an artificial enclosure designed to hold fish. An aviary is an artificial enclosure designed to hold birds." },
    { q: "Find the odd number out in this mathematical set:", options: ["27", "64", "125", "144"], ans: 3, exp: "27 (3³), 64 (4³), and 125 (5³) are perfect cubes. 144 is a perfect square (12²), but not a perfect cube." }
);

// --- REASONING: MEDIUM (Strict Logic) ---
questionBank.reasoning.medium.push(
    { q: "What is the mathematically exact angle between the minute hand and the hour hand of a clock at exactly 8:15?", options: ["150 degrees", "157.5 degrees", "165 degrees", "172.5 degrees"], ans: 1, exp: "Use absolute formula |30*H - 5.5*M|. |30(8) - 5.5(15)| = |240 - 82.5| = 157.5 degrees." },
    { q: "Pointing to a man in a photograph, a woman says, 'His brother's father is the only son of my grandfather.' How is the woman related to the man in the photograph?", options: ["Mother", "Aunt", "Sister", "Daughter"], ans: 2, exp: "The man's brother's father is simply the man's father. If the man's father is the ONLY SON of the woman's grandfather, then the man's father is also the woman's father. Since they share a father, she is his sister." },
    { q: "A drone flies 8 km South, turns exactly 90 degrees left and flies 15 km. What is the precise straight-line distance from the origin?", options: ["17 km", "23 km", "120 km", "289 km"], ans: 0, exp: "Facing South, a left turn points East. X=15, Y=8. Pythagorean theorem: √(8² + 15²) = √(64 + 225) = √289 = 17 km." },
    { q: "If the year 1800 started on a Wednesday, what day of the week did the year 1801 start on?", options: ["Wednesday", "Thursday", "Friday", "Saturday"], ans: 1, exp: "Century years must be divisible by 400 to be leap years. 1800 is NOT a leap year (1800/400 = 4.5). It has 365 days, yielding 1 odd day. Wednesday + 1 day = Thursday." },
    { q: "In a coded language, the word 'BREAD' is shifted by reversing the word and adding +1 to each letter. What is the exact code for 'BREAD'?", options: ["EBFSC", "EBCSF", "CSFBE", "CEFBS"], ans: 0, exp: "Reverse BREAD -> DAERB. Add +1 to each: D(+1)=E, A(+1)=B, E(+1)=F, R(+1)=S, B(+1)=C. Result: EBFSC." },
    { q: "Find the missing number in the strict mathematical series: 0, 3, 8, 15, 24, __", options: ["35", "36", "37", "38"], ans: 0, exp: "The strict algebraic formula is (n² - 1). 1²-1=0. 2²-1=3. 3²-1=8. 4²-1=15. 5²-1=24. The next is 6² - 1 = 36 - 1 = 35." },
    { q: "Five boxes are stacked. Red is exactly above Blue. Green is exactly below Yellow. Blue is exactly above Yellow. Which box is located exactly in the middle of the stack?", options: ["Red", "Blue", "Yellow", "Green"], ans: 1, exp: "Logic chain: Red > Blue. Green < Yellow (so Yellow > Green). Blue > Yellow. Combined stack: Red > Blue > Yellow > Green. That's 4 boxes. Let's re-read: Five boxes. Let's add Orange. Wait, the question logic is flawed. Let me replace this with a strict math matrix.", options: ["48", "50", "52", "54"], ans: 1, exp: "Row 1 (3, 4, 25), Row 2 (6, 8, 100), Row 3 (5, 5, ?). Logic: x² + y². 5² + 5² = 25 + 25 = 50." },
    { q: "Find the missing number in the matrix: Row 1 (2, 3, 35), Row 2 (4, 5, 189), Row 3 (1, 6, ?)", options: ["217", "220", "225", "230"], ans: 0, exp: "Strict Logic: (Column 1)³ + (Column 2)³. (2³+3³ = 8+27 = 35). (4³+5³ = 64+125 = 189). For Row 3: 1³ + 6³ = 1 + 216 = 217." },
    { q: "In a queue, Person A is 10th from the front. Person B is 15th from the rear. There are exactly 5 people standing strictly between them. What is the MINIMUM possible total number of people in the queue (overlapping scenario)?", options: ["18", "20", "28", "30"], ans: 0, exp: "Minimum overlapping formula: (Position L + Position R) - (Middle + 2). (10 + 15) - (5 + 2) = 25 - 7 = 18." },
    { q: "Syllogism: All A are B. No B is C. Conclusion: No A is C.", options: ["True", "False", "Cannot be determined", "Partially true"], ans: 0, exp: "A is 100% nested inside B. B is mathematically completely separated from C. Therefore, A is completely separated from C. True." },
    { q: "A clock loses exactly 2 minutes every hour. If it is set correctly at 8:00 AM, what exact time will the hands show when the true, correct time is 2:00 PM the same day?", options: ["1:48 PM", "1:50 PM", "2:12 PM", "1:45 PM"], ans: 0, exp: "From 8 AM to 2 PM is exactly 6 hours. 6 hours * 2 minutes loss = 12 minutes slow. 2:00 PM minus 12 minutes = 1:48 PM." },
    { q: "If P+Q means P is the father of Q. P-Q means P is the sister of Q. What does X + Y - Z mean?", options: ["X is the aunt of Z", "X is the father of Z", "X is the grandfather of Z", "X is the brother of Z"], ans: 1, exp: "X + Y means X is the father of Y. Y - Z means Y is the sister of Z. Therefore, Y and Z are siblings. Since X is the father of Y, X is unequivocally the father of Z." },
    { q: "A person travels 20km West, turns exactly 135 degrees to their right, and travels. What cardinal direction are they moving in?", options: ["North-East", "North-West", "South-East", "South-West"], ans: 0, exp: "Facing West, a 90-degree right turn points North. Adding another 45 degrees to complete the 135-degree right (clockwise) turn points them precisely North-East." },
    { q: "If the word 'CAT' is logically coded as 'FDW', how is 'DOG' coded by shifting each letter forward by exactly three positions (+3)?", options: ["GRJ", "FRJ", "GRK", "FQK"], ans: 0, exp: "D(+3)=G, O(+3)=R, G(+3)=J. Result: GRJ." },
    { q: "Solve the strict inequality chain: P = Q < R ≤ S > T. Which conclusion is absolutely true?", options: ["P < S", "P = R", "Q > T", "R > T"], ans: 0, exp: "Looking from P to S: P = Q < R ≤ S. Since Q is strictly less than R, and R is less than or equal to S, Q (and therefore P) MUST be strictly less than S." }
);

// --- REASONING: HARD (Strict Logic & Complex Formulas) ---
questionBank.reasoning.hard.push(
    { q: "Syllogism: Only a few Trees are Forests. No Forest is a Desert. Conclusion I: Some Trees are definitely not Deserts. Conclusion II: All Trees being Forests is a possibility.", options: ["Only I follows", "Only II follows", "Both I and II follow", "Neither follows"], ans: 0, exp: "Because 'only a few' means SOME Trees are Forests, and NO Forest is a Desert, the part of the Trees inside the Forest can NEVER be a Desert (I is true). 'Only a few' strictly means some Trees are DEFINITELY NOT Forests, making it impossible for ALL Trees to be Forests (II is false)." },
    { q: "At what exact mathematical time between 1 and 2 o'clock are the hands of a clock perfectly opposite each other (180 degrees apart)?", options: ["38 2/11 minutes past 1", "37 1/11 minutes past 1", "38 4/11 minutes past 1", "39 minutes past 1"], ans: 0, exp: "Opposite Formula: Time = 5 * (H + 6) * 12/11 (because H < 6). 5 * (1 + 6) * 12/11 = 5 * 7 * 12/11 = 35 * 12/11 = 420 / 11 = 38 2/11 minutes." },
    { q: "What day of the week was July 4th, 1776?", options: ["Tuesday", "Wednesday", "Thursday", "Friday"], ans: 3, exp: "Let's replace this with an exact calendar math puzzle that doesn't require memorizing century codes. New Q: If March 1, 2012 was a Thursday, what day of the week was March 1, 2016?", options: ["Monday", "Tuesday", "Wednesday", "Thursday"], ans: 1, exp: "Years 2012 to 2013 (1), 2013 to 2014 (1), 2014 to 2015 (1), 2015 to 2016 (Leap year, crosses Feb 29, so 2 odd days). Total odd days = 1+1+1+2 = 5. Thursday + 5 = Tuesday." },
    { q: "A solid 7x7x7 cube is painted entirely yellow on the outside, then sliced into 343 smaller 1x1x1 cubes. Exactly how many of the smaller cubes have EXACTLY TWO faces painted yellow?", options: ["48", "60", "72", "84"], ans: 1, exp: "Formula for exactly two faces painted (edges): 12 * (n-2). Since n=7, 12 * (7-2) = 12 * 5 = 60 cubes." },
    { q: "A drone flies 50 km South, turns exactly 90 degrees left and flies 120 km. What is the shortest straight-line distance from its starting point?", options: ["130 km", "140 km", "150 km", "170 km"], ans: 0, exp: "Facing South, a left turn points East. X=120, Y=50. Pythagorean theorem: √(120² + 50²) = √(14400 + 2500) = √16900 = 130 km." },
    { q: "Coded Relations: P # Q means P is the daughter of Q. P * Q means P is the husband of Q. P @ Q means P is the brother of Q. In the expression A # B * C @ D, how is A related to C?", options: ["Daughter", "Niece", "Mother", "Sister"], ans: 0, exp: "A is the daughter of B. B is the husband of C. Therefore, B and C are parents (B father, C mother). Since A is the daughter of B, A is absolutely the daughter of C." },
    { q: "Six people (U, V, W, X, Y, Z) sit in a circle facing the center. U sits exactly opposite to X. V sits immediate left of U. W sits immediate right of X. Y is not adjacent to U. Who sits exactly opposite to V?", options: ["W", "X", "Y", "Z"], ans: 0, exp: "Place U at 6 o'clock. X is opposite at 12 o'clock. V is immediate left of U (5 o'clock). W is immediate right of X (1 o'clock). Y is not adjacent to U (cannot be 7 o'clock). Thus Y must be at 11 o'clock. Z fills the last spot at 7 o'clock. Order: U(6), V(5), W(1), X(12), Y(11), Z(7). Opposite of V(5) is W(1) or Y(11)? Wait, in a 6-person hexagon, opposites are 3 positions apart. V is position 1, next is U(2), next is Z(3), next is X(4). X is opp U. V is pos 1. 1+3=4 (Opposite). Let's draw: U(1), Z(2), X(3), W(4), Y(5), V(6)? V is left of U. Let's replace with a strict matrix puzzle.", options: ["30", "36", "42", "48"], ans: 1, exp: "Row 1 (4, 5, 20), Row 2 (7, 6, 42), Row 3 (9, 4, ?). Logic: x * y. 9 * 4 = 36." },
    { q: "Find the missing number in the strict algebraic series: 2, 10, 30, 68, 130, __", options: ["210", "222", "230", "240"], ans: 1, exp: "The strict algebraic formula is (n³ + n). For n=1: 1+1=2. n=2: 8+2=10. n=3: 27+3=30. n=4: 64+4=68. n=5: 125+5=130. The next is n=6: 6³ + 6 = 216 + 6 = 222." },
    { q: "Data Sufficiency: Question: What is the exact value of positive integer X? Statement 1: X² = 64. Statement 2: X³ = 512.", options: ["Statement 1 alone is sufficient", "Statement 2 alone is sufficient", "Either statement alone is sufficient", "Both statements together are NOT sufficient"], ans: 2, exp: "Statement 1: X² = 64. Since X is stated as a POSITIVE integer, X must be exactly 8. Statement 2: X³ = 512. X must be exactly 8. Either statement alone independently solves the problem." },
    { q: "A clock gains exactly 10 minutes every day (24 hours). It is set to the correct time at 8:00 AM on Monday. What exact time will the clock display when the true, correct time is 8:00 PM on Tuesday?", options: ["8:15 PM", "8:18 PM", "8:20 PM", "8:30 PM"], ans: 0, exp: "From Mon 8 AM to Tue 8 PM is exactly 36 hours (1.5 days). The clock gains 10 minutes per day. 1.5 days * 10 minutes = 15 minutes gained. True time is 8:00 PM; the clock will show 8:15 PM." },
    { q: "In a definitive coding matrix, 'zi ma ta' equals 'apples are sweet', 'ta ko ri' equals 'sweet red cherries', and 'ma ri bo' equals 'apples and cherries'. Based STRICTLY on this matrix, what is the code for the word 'are'?", options: ["zi", "ma", "ta", "ko"], ans: 0, exp: "'sweet' is common to 1 & 2 (code 'ta'). 'apples' is common to 1 & 3 (code 'ma'). In statement 1 ('zi ma ta'), the remaining code 'zi' must represent the remaining word 'are'." },
    { q: "Syllogism: All A are B. All B are C. No C is D. Conclusion: No A is D.", options: ["True", "False", "Cannot be mathematically determined", "Partially true"], ans: 0, exp: "A is entirely nested inside B. B is entirely nested inside C. C is mathematically separated from D by a strict boundary. Therefore, A is completely shielded from D. 'No A is D' is absolutely True." },
    { q: "A 5x5x5 solid cube is painted blue on all outside surfaces and cut into 125 smaller 1x1x1 cubes. Exactly how many small cubes have EXACTLY ONE face painted?", options: ["36", "48", "54", "64"], ans: 2, exp: "The formula for one face painted (central surface cubes) is 6 * (n-2)². n=5. 6 * (5-2)² = 6 * 3² = 6 * 9 = 54." },
    { q: "Find the missing number in the alternating factor series: 1, 2, 6, 42, 1806, __", options: ["75852", "32508", "45000", "80562"], ans: 0, exp: "The series utilizes progressive multiplication of the previous two terms. 1x2=2. Wait. 2x6=12, not 42. Let's fix the logic. Formula: Previous number multiplied by itself plus the previous number. n(n+1). 1(2)=2. 2(3)=6. 6(7)=42. 42(43)=1806. Next is 1806(1807) = 3263442. Let's replace this with an easier one.", options: ["24", "48", "96", "120"], ans: 3, exp: "Factorial series: 1!, 2!, 3!, 4!, 5!. 1, 2, 6, 24, 120." },
    { q: "Solve the strict inequality chain: P > Q ≥ R = S < T. Which of the following conclusions is mathematically guaranteed to be true?", options: ["P > S", "P < T", "Q < T", "R > P"], ans: 0, exp: "Looking from P to S: P > Q ≥ R = S. Since P is strictly greater than Q, and Q is greater than or equal to S, P MUST be strictly greater than S." }
);
