    { q: "Evaluate the mathematical expression using strict BODMAS rules: 30 + 6 * 3 - 12 / 4", options: ["45", "46", "47", "48"], ans: 0, exp: "Multiply/Divide first: 30 + 18 - 3. Add/Subtract: 48 - 3 = 45." },
    { q: "Strict Analogy: Telescope is to Stars as Microscope is to:", options: ["Mountains", "Bacteria", "Oceans", "Clouds"], ans: 1, exp: "A telescope magnifies massively distant objects. A microscope magnifies infinitesimally small objects." },
    { q: "Find the next precise number in the arithmetic series: 120, 105, 90, 75, __", options: ["50", "55", "60", "65"], ans: 2, exp: "The constant difference between terms is exactly -15. 75 - 15 = 60." },
    { q: "If the word 'DOG' is mathematically coded as 26 (D=4, O=15, G=7), what is the exact value of the word 'COW'?", options: ["40", "41", "42", "43"], ans: 1, exp: "Position sum: C(3) + O(15) + W(23) = 41." },
    { q: "Identify the odd month out based strictly on the mathematical number of days:", options: ["February", "April", "June", "November"], ans: 0, exp: "February has 28 or 29 days. April, June, and November all have exactly 30 days." }
