// --- REASONING: MEDIUM (Strict Logic) ---
questionBank.reasoning.medium.push(
    { q: "What is the mathematically exact angle between the minute hand and the hour hand of a clock at exactly 10:20?", options: ["160 degrees", "170 degrees", "180 degrees", "190 degrees"], ans: 1, exp: "Formula: |30H - 5.5M|. |30(10) - 5.5(20)| = |300 - 110| = 190 degrees. This is the reflex angle. The inner angle is 360 - 190 = 170 degrees." },
    { q: "Pointing to a man, a woman says, 'His mother is the only daughter of my mother.' How is the woman related to the man?", options: ["Aunt", "Sister", "Mother", "Grandmother"], ans: 2, exp: "'The only daughter of my mother' refers to the woman herself. Therefore, the woman is the man's mother." },
    { q: "A traveler moves 8 km East, turns exactly 90 degrees right and moves 15 km. What is the precise straight-line distance from the origin?", options: ["17 km", "23 km", "120 km", "289 km"], ans: 0, exp: "Facing East, a right turn points South. X=8, Y=15. Pythagorean theorem: √(8² + 15²) = √(64 + 225) = √289 = 17 km." },
    { q: "If the year 2003 (a standard year) started on a Wednesday, what day of the week did the year 2004 start on?", options: ["Wednesday", "Thursday", "Friday", "Saturday"], ans: 1, exp: "2003 contains 365 days, creating exactly 1 odd day. Wednesday + 1 day = Thursday." },
    { q: "In a coded language, all vowels are shifted +1, and all consonants are shifted -1. How would the word 'MINT' be coded?", options: ["LHMS", "LJOV", "LHOV", "LJMS"], ans: 2, exp: "M(-1)=L. I(+1)=J. N(-1)=M. T(-1)=S. Result: LJMS. Wait, let me check the options. None match perfectly. Let's recalculate MINT: M(-1)=L. I(+1)=J. N(-1)=M. T(-1)=S. LJMS. Let's replace the options.", options: ["LHMS", "LJMS", "NKOV", "NKOS"], ans: 1, exp: "M(-1)=L. I(+1)=J. N(-1)=M. T(-1)=S. Result: LJMS." },
    { q: "Find the missing number in the strict mathematical series: 1, 8, 27, 64, 125, __", options: ["144", "196", "216", "256"], ans: 2, exp: "This is a direct sequence of perfect cubes: 1³, 2³, 3³, 4³, 5³. The next is 6³ = 216." },
    { q: "Five boxes are ranked by weight. A is heavier than B but lighter than C. D is heavier than E but lighter than B. Which box is the absolute lightest?", options: ["A", "B", "D", "E"], ans: 3, exp: "Logic chain: C > A > B. And B > D > E. Combined: C > A > B > D > E. E is the lightest." },
    { q: "Find the missing number in the matrix: Row 1 (5, 6, 61), Row 2 (4, 3, 25), Row 3 (8, 2, ?)", options: ["60", "64", "68", "72"], ans: 2, exp: "Strict Logic: (Column 1)² + (Column 2)². (5²+6² = 25+36 = 61). For Row 3: 8² + 2² = 64 + 4 = 68." },
    { q: "In a queue, Person X is 10th from the front. Person Y is 20th from the rear. There are exactly 2 people standing strictly between them. What is the MINIMUM possible total number of people in the queue (overlapping scenario)?", options: ["24", "26", "28", "30"], ans: 1, exp: "Minimum overlapping formula: (Position L + Position R) - (Middle + 2). (10 + 20) - (2 + 2) = 30 - 4 = 26." },
    { q: "Syllogism: All Birds are Animals. All Animals are Living. Conclusion: All Birds are Living.", options: ["True", "False", "Cannot be determined", "Partially true"], ans: 0, exp: "Birds are 100% nested inside Animals. Animals are 100% nested inside Living. Therefore, Birds are unequivocally 100% inside Living. True." },
    { q: "A clock gains exactly 2 minutes every hour. If it is set correctly at 8:00 AM, what exact time will the hands show when the true, correct time is 4:00 PM the same day?", options: ["4:00 PM", "4:08 PM", "4:16 PM", "4:24 PM"], ans: 2, exp: "From 8 AM to 4 PM is exactly 8 hours. 8 hours * 2 minutes gain = 16 minutes fast. It will display 4:16 PM." },
    { q: "If A+B means A is the brother of B. A*B means A is the father of B. What does X * Y + Z mean?", options: ["X is the uncle of Z", "X is the father of Z", "X is the grandfather of Z", "X is the brother of Z"], ans: 1, exp: "X * Y means X is the father of Y. Y + Z means Y is the brother of Z. Therefore, Y and Z are siblings. Since X is the father of Y, X is unequivocally the father of Z." },
    { q: "A person travels 20km West, turns exactly 90 degrees to their left, and travels. What cardinal direction are they moving in?", options: ["North", "South", "East", "West"], ans: 1, exp: "Facing West, a 90-degree left (anticlockwise) turn points the person precisely South." },
    { q: "If the word 'DOG' is logically coded as 'EPH', how is 'CAT' coded by shifting each letter forward by exactly one position (+1)?", options: ["DBU", "DBU", "DBU", "DBU (Wait, need proper options)"], ans: 0, exp: "C(+1)=D, A(+1)=B, T(+1)=U. Result: DBU. Let me fix the options.", options: ["DBU", "DCU", "EBU", "ECU"], ans: 0, exp: "C(+1)=D, A(+1)=B, T(+1)=U. Result: DBU." },
    { q: "Solve the strict inequality chain: P > Q ≥ R = S < T. Which conclusion is absolutely true?", options: ["P > S", "P < T", "Q < T", "R > P"], ans: 0, exp: "Looking from P to S: P > Q ≥ R = S. Since P is strictly greater than Q, and Q is greater than or equal to S, P MUST be strictly greater than S." }
);

// --- REASONING: HARD (Strict Logic & Complex Formulas) ---
questionBank.reasoning.hard.push(
    { q: "Syllogism: No A is B. Only a few B are C. Conclusion I: Some C are definitely not A. Conclusion II: All C can never be B.", options: ["Only I follows", "Only II follows", "Both I and II follow", "Neither follows"], ans: 0, exp: "B does not touch A. C overlaps B. The part of C that sits inside B can NEVER touch A. Therefore, some C are definitely not A (I is true). 'Only a few B are C' means some B are not C. It does NOT restrict C from being entirely inside B. Thus, all C COULD potentially be B (II is false)." },
    { q: "At what exact mathematical time between 7 and 8 o'clock are the hands of a clock perfectly aligned (0 degrees apart)?", options: ["38 2/11 minutes past 7", "37 1/11 minutes past 7", "39 3/11 minutes past 7", "40 minutes past 7"], ans: 0, exp: "Alignment Formula: Time = 5 * H * (12/11). 5 * 7 * 12/11 = 420 / 11 = 38 2/11 minutes." },
    { q: "If March 1, 2004 was a Monday, what exact day of the week was March 1, 2008?", options: ["Thursday", "Friday", "Saturday", "Sunday"], ans: 2, exp: "Years 2004 to 2005 (1), 2005 to 2006 (1), 2006 to 2007 (1), 2007 to 2008 (Leap year, crosses Feb 29, so 2 odd days). Total odd days = 1+1+1+2 = 5. Monday + 5 = Saturday." },
    { q: "A solid 5x5x5 cube is painted entirely blue on the outside, then sliced into 125 smaller 1x1x1 cubes. Exactly how many of the smaller cubes have EXACTLY TWO faces painted blue?", options: ["24", "36", "48", "60"], ans: 1, exp: "Formula for exactly two faces painted (edges): 12 * (n-2). Since n=5, 12 * (5-2) = 12 * 3 = 36 cubes." },
    { q: "A drone flies 40 km North, turns exactly 90 degrees right and flies 30 km. It then turns exactly 90 degrees right and flies 40 km. What is the shortest straight-line distance from its starting point?", options: ["10 km", "20 km", "30 km", "40 km"], ans: 2, exp: "The drone flies a rectangular path. North 40 and South 40 (second right turn faces South) cancel out exactly. It is left with exactly 30 km East of the starting point." },
    { q: "Coded Relations: P # Q means P is the daughter of Q. P * Q means P is the husband of Q. P @ Q means P is the brother of Q. In the expression A # B * C @ D, how is A related to C?", options: ["Daughter", "Niece", "Mother", "Sister"], ans: 0, exp: "A is the daughter of B. B is the husband of C. Therefore, B and C are parents (B father, C mother). Since A is the daughter of B, A is absolutely the daughter of C." },
    { q: "Find the missing number in the matrix: Row 1 (3, 4, 12), Row 2 (7, 6, 42), Row 3 (9, 8, ?)", options: ["64", "72", "81", "90"], ans: 1, exp: "Strict Logic: x * y. 9 * 8 = 72." },
    { q: "Find the missing number in the strict algebraic series: 0, 7, 26, 63, 124, __", options: ["215", "216", "217", "218"], ans: 0, exp: "The strict algebraic formula is (n³ - 1). For n=1: 1-1=0. n=2: 8-1=7. n=3: 27-1=26. n=4: 64-1=63. n=5: 125-1=124. The next is n=6: 6³ - 1 = 216 - 1 = 215." },
    { q: "Data Sufficiency: Question: What is the exact value of positive integer Y? Statement 1: Y² = 100. Statement 2: Y³ = 1000.", options: ["Statement 1 alone is sufficient", "Statement 2 alone is sufficient", "Either statement alone is sufficient", "Both statements together are NOT sufficient"], ans: 2, exp: "Statement 1: Y² = 100. Since Y is stated as a POSITIVE integer, Y must be exactly 10. Statement 2: Y³ = 1000. Y must be exactly 10. Either statement alone independently solves the problem." },
    { q: "A clock loses exactly 10 minutes every day (24 hours). It is set to the correct time at 8:00 AM on Monday. What exact time will the clock display when the true, correct time is 8:00 PM on Tuesday?", options: ["7:45 PM", "7:48 PM", "7:50 PM", "8:15 PM"], ans: 0, exp: "From Mon 8 AM to Tue 8 PM is exactly 36 hours (1.5 days). The clock loses 10 minutes per day. 1.5 days * 10 minutes = 15 minutes lost. True time is 8:00 PM; the clock will show 7:45 PM." },
    { q: "In a definitive coding matrix, 'ka re ta' equals 'birds fly high', 'ta mo ri' equals 'high red mountains', and 'ka ri bo' equals 'birds and mountains'. Based STRICTLY on this matrix, what is the code for the word 'fly'?", options: ["ka", "re", "ta", "mo"], ans: 1, exp: "'high' is common to 1 & 2 (code 'ta'). 'birds' is common to 1 & 3 (code 'ka'). In statement 1 ('ka re ta'), the remaining code 're' must represent the remaining word 'fly'." },
    { q: "Syllogism: All A are B. All B are C. No C is D. Conclusion: No A is D.", options: ["True", "False", "Cannot be mathematically determined", "Partially true"], ans: 0, exp: "A is entirely nested inside B. B is entirely nested inside C. C is mathematically separated from D by a strict boundary. Therefore, A is completely shielded from D. 'No A is D' is absolutely True." },
    { q: "A 6x6x6 solid cube is painted yellow on all outside surfaces and cut into 216 smaller 1x1x1 cubes. Exactly how many small cubes have EXACTLY ONE face painted?", options: ["64", "96", "100", "125"], ans: 1, exp: "The formula for one face painted (central surface cubes) is 6 * (n-2)². n=6. 6 * (6-2)² = 6 * 4² = 6 * 16 = 96." },
    { q: "Find the missing number in the alternating factor series: 1, 2, 6, 24, 120, __", options: ["240", "480", "720", "840"], ans: 2, exp: "Factorial series: 1!, 2!, 3!, 4!, 5!. 1x2=2. 2x3=6. 6x4=24. 24x5=120. Next is 120x6 = 720." },
    { q: "Solve the strict inequality chain: P > Q ≥ R = S < T. Which of the following conclusions is mathematically guaranteed to be true?", options: ["P > S", "P < T", "Q < T", "R > P"], ans: 0, exp: "Looking from P to S: P > Q ≥ R = S. Since P is strictly greater than Q, and Q is greater than or equal to S, P MUST be strictly greater than S." }
);
